
(function(){'use strict';if(typeof CMA==='undefined'){window.CMA={}}
CMA.Users={initUserActions:function(recordId){this.updateGroupsFieldVisibility();var userLevelField=document.querySelector('[name="userLevel"]');if(userLevelField){var container=userLevelField.closest('.radiogroup, .form-row');if(container){container.addEventListener('change',this.updateGroupsFieldVisibility.bind(this))}}
if(!recordId||recordId==='new'){this.removeActionButtons();return}
var isAdmin=window.CMA_IS_ADMIN||(window.top&&window.top.CMA_IS_ADMIN);var isDeveloper=window.CMA_IS_DEVELOPER||(window.top&&window.top.CMA_IS_DEVELOPER);if(!isAdmin&&!isDeveloper){return}
this.addActionButtons(recordId,isDeveloper)},updateGroupsFieldVisibility:function(){var userLevelField=document.querySelector('[name="userLevel"]:checked');var groupsRow=document.querySelector('[name="user_groups"]');if(!groupsRow){groupsRow=document.getElementById('user_groups')}
if(!groupsRow)return;var formRow=groupsRow.closest('.form-row, tr');if(!formRow)return;var userLevel=userLevelField?parseInt(userLevelField.value,10):0;if(userLevel>=1){formRow.style.display='none'}else{formRow.style.display=''}},addActionButtons:function(recordId,isDeveloper){var toolbar=document.querySelector('#detailToolbar .toolbar-left');if(!toolbar){cmaLog.warn('CMA.Users: Could not find #detailToolbar .toolbar-left');return}
this.removeActionButtons();var separator=document.createElement('span');separator.className='tb-sep requires-record user-action-buttons';toolbar.appendChild(separator);var loginAsBtn=document.createElement('span');loginAsBtn.className='tb-btn responsive-btn requires-record user-action-buttons';loginAsBtn.title='Log in als deze gebruiker';loginAsBtn.innerHTML='<a href="#" data-action="loginAs"><span class="lnr lnr-enter"></span><span class="btn-text">Inloggen als</span></a>';loginAsBtn.querySelector('a').onclick=function(e){e.preventDefault();CMA.Users.loginAsUser(recordId)};toolbar.appendChild(loginAsBtn)},removeActionButtons:function(){document.querySelectorAll('.user-action-buttons').forEach(function(el){el.remove()})},resetPassword:async function(userId){var confirmed=await libConfirm('Weet je zeker dat je het wachtwoord wilt resetten? Er wordt een tijdelijk wachtwoord gegenereerd.',{title:'Wachtwoord resetten',type:'warning',confirmText:'Resetten',cancelText:'Annuleren'});if(!confirmed)return;try{var response=await fetch('/cma/api/user_actions.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'reset_password',userId:userId})});var result=await response.json();if(result.success){await libAlert('<p>'+result.message+'</p>'+'<p style="margin-top: 15px;"><strong>Tijdelijk wachtwoord:</strong></p>'+'<code style="display: block; padding: 10px; background: var(--bg-surface-alt); border-radius: 4px; font-size: var(--font-size-lg); text-align: center; user-select: all;">'+result.tempPassword+'</code>'+'<p style="margin-top: 15px; font-size: var(--font-size-sm); color: var(--text-muted);">'+result.note+'</p>',{title:'Wachtwoord gereset',type:'success',html:!0})}else{await libAlert(result.error||'Wachtwoord resetten mislukt',{title:'Fout',type:'danger'})}}catch(e){cmaLog.error('Reset password error:',e);await libAlert('Er is een fout opgetreden: '+e.message,{title:'Fout',type:'danger'})}},loginAsUser:async function(userId){var confirmed=await libConfirm('Je gaat inloggen als deze gebruiker. Wil je doorgaan?',{title:'Inloggen als gebruiker',type:'info',confirmText:'Inloggen',cancelText:'Annuleren'});if(!confirmed)return;try{var response=await fetch('/cma/api/user_actions.php',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({action:'login_as',userId:userId})});var result=await response.json();if(result.success){await libAlert('<p>'+result.message+'</p>'+'<p style="margin-top: 10px; font-size: var(--font-size-sm); color: var(--text-muted);">'+result.note+'</p>',{title:'Ingelogd',type:'success',html:!0});if(result.redirect){window.top.location.href=result.redirect}else{window.top.location.reload()}}else{await libAlert(result.error||'Inloggen mislukt',{title:'Fout',type:'danger'})}}catch(e){cmaLog.error('Login as error:',e);await libAlert('Er is een fout opgetreden: '+e.message,{title:'Fout',type:'danger'})}}}})()
